package com.noor.alhidayah.ui.theme
import android.app.Activity;import androidx.compose.material3.MaterialTheme;import androidx.compose.material3.darkColorScheme
import androidx.compose.runtime.Composable;import androidx.compose.runtime.SideEffect;import androidx.compose.ui.graphics.toArgb
import androidx.compose.ui.platform.LocalView;import androidx.core.view.WindowCompat
private val NoorDarkColorScheme=darkColorScheme(primary=SkyBlue,onPrimary=NightSkyDark,primaryContainer=SkyBlueContainer,onPrimaryContainer=SkyBlueLight,secondary=Emerald,onSecondary=NightSkyDark,secondaryContainer=EmeraldContainer,onSecondaryContainer=EmeraldLight,tertiary=Gold,onTertiary=NightSkyDark,tertiaryContainer=GoldContainer,onTertiaryContainer=GoldLight,error=ErrorRed,onError=NightSkyDark,errorContainer=ErrorRedContainer,background=NightSky,onBackground=OnDarkText,surface=NightSkySurface,onSurface=OnDarkText,surfaceVariant=NightSkySurfaceVariant,onSurfaceVariant=OnDarkTextSecondary,outline=GlassBorder,inverseSurface=OnDarkText,inverseOnSurface=NightSky,inversePrimary=SkyBlueDark,scrim=NightSkyDark)
@Composable fun NoorAlHidayahTheme(content:@Composable ()->Unit){val view=LocalView.current;if(!view.isInEditMode){SideEffect{val w=(view.context as Activity).window;w.statusBarColor=NoorDarkColorScheme.background.toArgb();w.navigationBarColor=NoorDarkColorScheme.background.toArgb();WindowCompat.getInsetsController(w,view).apply{isAppearanceLightStatusBars=false;isAppearanceLightNavigationBars=false}}};MaterialTheme(colorScheme=NoorDarkColorScheme,content=content)}